VALUES
  ('generalpolice-94737317-moex-00072', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依憲法第129條規定，憲法所規定之各種選舉，除憲法別有規定外，以普通、平等、直接及無記名投 票之方法行之，下列敘述何者錯誤？', '["所謂「普通選舉」，指所有具有中華民國國籍之人民，如符合法定年齡，且無法定排除事由者，則 均有選舉權及被選舉權", "所謂「平等選舉」，即每人一票，票票等值，如各該選舉定有婦女保障名額，即違反平等選舉原則", "所謂「直接選舉」，即選舉結果係由人民直接的選舉行為所產生，而無任何其他機關或第三人之中介", "所謂「無記名選舉」，即選票上不能有關於投票人姓名或其他足以辨識投票人資訊之記載，以確保 選舉的自主性以及秘密性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00073', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依司法院大法官解釋，有關憲法第22條，下列敘述何者正確？', '["環境權為大法官解釋承認之憲法第22條權利", "憲法第22條保障對象以本國籍自然人與法人為限", "人格發展自由係憲法第22條保障之權利", "憲法第22條保障之權利，限於符合公共道德與善良風俗者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00074', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依憲法本文及增修條文，總統所發布之命令中，下列何者須經行政院院長之副署？', '["行政院院長的任免命令", "依憲法經立法院同意任命人員之任免命令", "戒嚴及緊急命令", "解散立法院之命令"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00075', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依司法院大法官解釋，有關立法院職權行使，下列敘述何者正確？', '["立法院對總統提名之監察委員人選，得消極不行使同意權", "公投法規定立法院有公投提案權，違憲", "偵查中之案件，立法院亦得向檢察機關調閱相關卷證", "立法院於臨時會中審議不信任案，非憲法所不許"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00076', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依憲法增修條文第5條第5項規定，政黨之目的或其行為如危害下列何者，即屬違憲？', '["政黨平等原則", "自由民主之憲政秩序", "社會福利原則", "創制複決等直接民主權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00077', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '總統、副總統彈劾案件，憲法法庭宣告彈劾成立之判決，應經下列何種方式之同意？', '["大法官現有總額3分之2以上", "大法官現有總額4分之3以上", "大法官參與評議人數3分之2以上", "大法官參與評議人數4分之3以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00078', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依相關憲法解釋與裁判見解及我國立法實務，以下何者不屬於國民主權原則的實踐？', '["國民法官參與刑事審判", "立法委員不得兼任官吏", "公民投票", "民意代表定期改選"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00079', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依憲法法庭判決，關於侮辱職務罪與言論自由之保障，下列敘述何者錯誤？', '["對於質疑、批評政府公權力行使之言論，宜抱持較寬容之態度，以確保憲法對言論自由最大限度之保障", "侮辱職務罪非僅是對表意時間、地點或方式之規制或處罰，甚至可能涉及觀點之管制", "侮辱職務之言論係對事不對人，國家僅得以保障公務執行之法益，做為侮辱職務罪所追求之合憲目的", "如將侮辱職務言論之處罰，限縮至處以罰金刑，即符合比例原則，未違反憲法保障言論自由之意旨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00080', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '關於租稅的實踐，依憲法學理及我國稅捐行政實務，下列敘述何者正確？', '["因義務人逾期納稅而加徵之滯納金部分，得加計利息命義務人繳納", "特別公課乃是稅捐以外對義務人課予繳納金錢之負擔，其徵收要件不得由法律授權以命令訂定，始 符租稅法定主義", "無償供公眾通行之道路土地免徵地價稅，但若屬建造房屋應保留之法定空地者則不免徵，符合平等原則", "國家對人民應不分經濟能力強弱，一律課予相同稅率，方符賦稅公平主義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00081', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '下列何者曾被大法官認定違反法律明確性而宣告違憲？', '["檢肅流氓條例有關「敲詐勒索、強迫買賣及其幕後操縱行為」之規定", "檢肅流氓條例有關「品行惡劣、遊蕩無賴」之規定", "刑法第235條「猥褻」之規定", "藥害救濟法「常見且可預期之藥物不良反應」之規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "ea05ba398baf", "answer_pdf_sha1": "035d3cba5d19", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
